#include <stdio.h>
#include <string.h>
#define MAX 200005
int main() {
    int n, m;
    char s[MAX], t[MAX];
    int a[10], b[10];
    scanf("%d %d", &n, &m);
    scanf("%s", s);
    scanf("%s", t);
    for (int i = 0; i < 10; i++) {
        scanf("%d", &a[i]);
    }
    for (int i = 0; i < 10; i++) {
        scanf("%d", &b[i]);
    }
    int min_time = 1000000000;
    for (int i = 0; i <= n - m; i++) {
        int time = 0;
        for (int j = 0; j < m; j++) {
            int diff = (t[j] - '0') - (s[i + j] - '0');
            if (diff < 0) diff += 10;
            time += a[s[i + j] - '0'] * diff;
        }
        min_time = (min_time < time) ? min_time : time;
    }
    printf("%d\n", min_time);
    return 0;
}

