import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int m = sc.nextInt();
        String s = sc.next();
        String t = sc.next();
        int[] a = new int[10];
        int[] b = new int[10];
        for (int i = 0; i < 10; i++) {
            a[i] = sc.nextInt();
        }
        for (int i = 0; i < 10; i++) {
            b[i] = sc.nextInt();
        }
        int min_time = 1000000000;
        for (int i = 0; i <= n - m; i++) {
            int time = 0;
            for (int j = 0; j < m; j++) {
                int diff = (t.charAt(j) - '0') - (s.charAt(i + j) - '0');
                if (diff < 0) diff += 10;
                time += a[s.charAt(i + j) - '0'] * diff;
            }
            min_time = Math.min(min_time, time);
        }
        System.out.println(min_time);
    }
}

